import logo from './logo.svg';
import './App.css';
import React, { useRef, useEffect, useState } from 'react';
import DeckGL from 'deck.gl';
import {LineLayer} from '@deck.gl/layers';
import {Map, StaticMap, MapContext, NavigationControl} from 'react-map-gl';

import 'mapbox-gl/dist/mapbox-gl.css';
import './index.css';
import mapboxgl from 'mapbox-gl';


const MAPBOX_ACCESS_TOKEN = 'pk.eyJ1IjoidmVudG9saW5lIiwiYSI6ImNsbjBzYnY3eDFzb24yc3F2OW1hZ3V2YWoifQ.pelghd1_gDY9DeAYv3rrAw';

// Viewport settings
const INITIAL_VIEW_STATE = {
  longitude: -122.41669,
  latitude: 37.7853,
  zoom: 13,
  pitch: 0,
  bearing: 0
};


// Data to be used by the LineLayer
const data = [
  {sourcePosition: [-122.41669, 37.7853], targetPosition: [-121.41669, 27.781]}
];


function App() {
  const layers = [
    new LineLayer({id: 'line-layer', data})
  ];



  return (
      <DeckGL
    initialViewState={INITIAL_VIEW_STATE}
  /*   mapStyle={"mapbox://styles/mapbox/streets-v12" }  */ 
    layers={layers} 
    >
          <Map 
          mapboxAccessToken={MAPBOX_ACCESS_TOKEN}  
          />
</DeckGL>   

  );
}

export default App;
